<?php
/**
 * Plugin Name: Tager V48 Discovery & Vendor Experience Upgrade
 * Description: Advanced vendor/product discovery, multi-service areas, sorting, pagination, verified vendors, delivery filters, and richer store pages.
 * Version: 48.0.0
 */
if (!defined('ABSPATH')) exit;

final class Tager_V48_Discovery_Upgrade {
    const VER='48.0.0';
    public static function init(){
        add_action('init',[__CLASS__,'register'],120);
        add_action('admin_post_tager_v48_save_profile',[__CLASS__,'save_profile']);
        add_shortcode('tager_v48_vendor_directory',[__CLASS__,'vendor_directory']);
        add_shortcode('tager_v48_market',[__CLASS__,'market']);
        add_shortcode('tager_v48_vendor_profile',[__CLASS__,'vendor_profile']);
        add_action('wp_enqueue_scripts',[__CLASS__,'assets'],120);
    }
    private static function page($slug,$title,$content){
        $p=get_page_by_path($slug);
        if(!$p){wp_insert_post(['post_type'=>'page','post_status'=>'publish','post_title'=>$title,'post_name'=>$slug,'post_content'=>$content]);}
        elseif(trim((string)$p->post_content)!==$content){wp_update_post(['ID'=>$p->ID,'post_content'=>$content]);}
    }
    public static function register(){
        self::page('vendor-directory','دليل الموردين','[tager_v48_vendor_directory]');
        self::page('products','المنتجات والسوق','[tager_v48_market]');
        self::page('vendor-location-settings','بيانات ومناطق المورد','[tager_v48_vendor_profile]');
    }
    private static function url($slug,$args=[]){$p=get_page_by_path($slug);$u=$p?get_permalink($p):home_url('/'.$slug.'/');return $args?add_query_arg($args,$u):$u;}
    private static function govs(){return class_exists('Tager_V47_Discovery')?Tager_V47_Discovery::govs():[];}
    private static function vendor_ok($uid){$u=get_userdata($uid);return $u && in_array('tager_vendor',(array)$u->roles,true);}
    private static function product_price($id,$tier){$k=$tier==='wholesale'?'wholesale_price':($tier==='bulk'?'bulk_price':'retail_price');return (float)get_post_meta($id,$k,true);}
    private static function vendor_products($uid){return get_posts(['post_type'=>'tager_product','author'=>$uid,'post_status'=>'publish','numberposts'=>-1,'meta_key'=>'approval_status','meta_value'=>'approved','fields'=>'ids']);}
    public static function assets(){
        wp_register_style('tager-v48',false,[],self::VER);wp_enqueue_style('tager-v48');
        wp_add_inline_style('tager-v48','.tv48{max-width:1280px;margin:auto;padding:24px 16px}.tv48-hero{background:linear-gradient(135deg,#0b4938,#137357);color:#fff;border-radius:26px;padding:34px;margin-bottom:22px}.tv48-filters{display:grid;grid-template-columns:2fr repeat(5,minmax(130px,1fr));gap:10px;background:#fff;border:1px solid #e3ebe7;padding:16px;border-radius:18px;box-shadow:0 10px 30px #103f3012}.tv48-filters input,.tv48-filters select,.tv48-form input,.tv48-form select,.tv48-form textarea{width:100%;padding:11px;border:1px solid #cbd8d2;border-radius:10px;background:#fff}.tv48-btn{display:inline-flex;align-items:center;justify-content:center;gap:7px;background:#b68c27;color:#fff!important;border:0;border-radius:10px;padding:11px 16px;text-decoration:none;cursor:pointer}.tv48-btn.alt{background:#145540}.tv48-grid{display:grid;grid-template-columns:repeat(3,minmax(0,1fr));gap:18px;margin-top:22px}.tv48-card{background:#fff;border:1px solid #e2ebe6;border-radius:18px;overflow:hidden;box-shadow:0 8px 24px #123f3010}.tv48-media{height:180px;background:#eef5f1;display:flex;align-items:center;justify-content:center}.tv48-media img{width:100%;height:100%;object-fit:cover}.tv48-body{padding:18px}.tv48-tags{display:flex;gap:6px;flex-wrap:wrap;margin:9px 0}.tv48-tag{font-size:12px;background:#edf6f1;color:#16523e;border-radius:999px;padding:5px 9px}.tv48-verified{background:#e8f3ff;color:#0f5e9c}.tv48-prices{display:grid;grid-template-columns:repeat(3,1fr);gap:7px;margin:12px 0}.tv48-price{background:#f7faf8;padding:9px;border-radius:9px;text-align:center;font-size:12px}.tv48-price strong{display:block;color:#0f513d;font-size:16px}.tv48-pager{display:flex;gap:8px;justify-content:center;margin:25px}.tv48-pager a,.tv48-pager span{padding:8px 12px;border:1px solid #d4dfda;border-radius:8px;text-decoration:none}.tv48-form{max-width:860px;background:#fff;padding:22px;border-radius:18px;border:1px solid #e2ebe6}.tv48-form label{display:block;font-weight:700;margin:13px 0}.tv48-checks{display:grid;grid-template-columns:repeat(3,1fr);gap:8px}.tv48-checks label{font-weight:400;margin:0;background:#f7faf8;padding:9px;border-radius:8px}.tv48-empty{padding:34px;text-align:center;border:1px dashed #bdcbc4;border-radius:15px;background:#fff}@media(max-width:1000px){.tv48-filters{grid-template-columns:1fr 1fr 1fr}.tv48-grid{grid-template-columns:1fr 1fr}}@media(max-width:650px){.tv48-filters,.tv48-grid,.tv48-checks{grid-template-columns:1fr}.tv48-prices{grid-template-columns:1fr}}');
        wp_register_script('tager-v48',false,['jquery'],self::VER,true);wp_enqueue_script('tager-v48');
        wp_add_inline_script('tager-v48','window.TV48_GOVS='.wp_json_encode(self::govs()).';document.addEventListener("change",function(e){if(!e.target.matches("[data-tv48-gov]"))return;var wrap=e.target.closest("form")||document;var center=wrap.querySelector("[data-tv48-center]");if(!center)return;var arr=window.TV48_GOVS[e.target.value]||[];center.innerHTML="<option value=\"\">كل المراكز</option>"+arr.map(function(x){return "<option>"+x+"</option>"}).join("");});');
    }
    public static function vendor_directory(){
        $q=sanitize_text_field($_GET['q']??'');$gov=sanitize_text_field($_GET['gov']??'');$center=sanitize_text_field($_GET['center']??'');$sort=sanitize_key($_GET['sort']??'name');$verified=!empty($_GET['verified']);$delivery=!empty($_GET['delivery']);$page=max(1,(int)($_GET['pg']??1));$per=12;
        $vendors=get_users(['role'=>'tager_vendor','number'=>500]);
        $vendors=array_values(array_filter($vendors,function($u)use($q,$gov,$center,$verified,$delivery){
            if($gov&&get_user_meta($u->ID,'tager_governorate',true)!==$gov)return false;
            if($center){$primary=get_user_meta($u->ID,'tager_center',true);$areas=(array)get_user_meta($u->ID,'tager_service_centers',true);if($primary!==$center&&!in_array($center,$areas,true))return false;}
            if($verified&&!get_user_meta($u->ID,'tager_vendor_verified',true))return false;
            if($delivery&&!get_user_meta($u->ID,'tager_delivery_available',true))return false;
            if($q){$hay=$u->display_name.' '.get_user_meta($u->ID,'store_name',true).' '.get_user_meta($u->ID,'store_description',true).' '.get_user_meta($u->ID,'store_categories',true);if(mb_stripos($hay,$q)===false)return false;}
            return true;
        }));
        usort($vendors,function($a,$b)use($sort){
            if($sort==='products')return count(self::vendor_products($b->ID))<=>count(self::vendor_products($a->ID));
            if($sort==='min_order')return (float)get_user_meta($a->ID,'vendor_min_order',true)<=>(float)get_user_meta($b->ID,'vendor_min_order',true);
            if($sort==='rating')return (float)get_user_meta($b->ID,'vendor_rating',true)<=>(float)get_user_meta($a->ID,'vendor_rating',true);
            return strcasecmp($a->display_name,$b->display_name);
        });
        $total=count($vendors);$vendors=array_slice($vendors,($page-1)*$per,$per);
        ob_start();?><div class="tv48"><section class="tv48-hero"><h1>دليل الموردين المتطور</h1><p>ابحث بالمحافظة والمركز والنشاط، واعرض الموردين الموثقين وخيارات التوصيل.</p></section><form class="tv48-filters"><input name="q" value="<?php echo esc_attr($q);?>" placeholder="اسم المورد أو النشاط"><select name="gov" data-tv48-gov><option value="">كل المحافظات</option><?php foreach(self::govs() as $g=>$cs)echo '<option '.selected($gov,$g,false).'>'.esc_html($g).'</option>';?></select><select name="center" data-tv48-center><option value="">كل المراكز</option><?php foreach((self::govs()[$gov]??[]) as $c)echo '<option '.selected($center,$c,false).'>'.esc_html($c).'</option>';?></select><select name="sort"><option value="name">ترتيب بالاسم</option><option value="products" <?php selected($sort,'products');?>>الأكثر منتجات</option><option value="rating" <?php selected($sort,'rating');?>>الأعلى تقييمًا</option><option value="min_order" <?php selected($sort,'min_order');?>>الأقل حدًا للطلب</option></select><label><input type="checkbox" name="verified" value="1" <?php checked($verified);?>> موثق</label><label><input type="checkbox" name="delivery" value="1" <?php checked($delivery);?>> توصيل متاح</label><button class="tv48-btn">بحث</button></form><div class="tv48-grid"><?php if(!$vendors)echo '<div class="tv48-empty">لا توجد نتائج مطابقة.</div>';foreach($vendors as $v){$logo=(int)get_user_meta($v->ID,'store_logo_id',true);$img=$logo?wp_get_attachment_image_url($logo,'medium'):'';$products=self::vendor_products($v->ID);$verified_v=get_user_meta($v->ID,'tager_vendor_verified',true);$rating=get_user_meta($v->ID,'vendor_rating',true)?:'—';?><article class="tv48-card"><div class="tv48-media"><?php echo $img?'<img src="'.esc_url($img).'" alt="">':'<span style="font-size:52px">🏪</span>';?></div><div class="tv48-body"><h3><?php echo esc_html(get_user_meta($v->ID,'store_name',true)?:$v->display_name);?></h3><div class="tv48-tags"><?php if($verified_v)echo '<span class="tv48-tag tv48-verified">✓ مورد موثق</span>';?><span class="tv48-tag"><?php echo esc_html(get_user_meta($v->ID,'tager_governorate',true).' - '.get_user_meta($v->ID,'tager_center',true));?></span><span class="tv48-tag"><?php echo count($products);?> منتج</span><span class="tv48-tag">تقييم <?php echo esc_html($rating);?></span></div><p><?php echo esc_html(wp_trim_words(get_user_meta($v->ID,'store_description',true),20));?></p><p><strong>الحد الأدنى:</strong> <?php echo esc_html((float)get_user_meta($v->ID,'vendor_min_order',true));?> ج.م</p><a class="tv48-btn" href="<?php echo esc_url(self::url('vendor-store',['vendor_id'=>$v->ID]));?>">فتح المتجر</a></div></article><?php }?></div><?php $pages=(int)ceil($total/$per);if($pages>1){echo '<div class="tv48-pager">';for($i=1;$i<=$pages;$i++)echo $i===$page?'<span>'.$i.'</span>':'<a href="'.esc_url(add_query_arg('pg',$i)).'">'.$i.'</a>';echo '</div>';}?></div><?php return ob_get_clean();
    }
    public static function market(){
        $q=sanitize_text_field($_GET['q']??'');$tier=sanitize_key($_GET['tier']??'');$gov=sanitize_text_field($_GET['gov']??'');$center=sanitize_text_field($_GET['center']??'');$sort=sanitize_key($_GET['sort']??'new');$stock=!empty($_GET['stock']);$page=max(1,(int)($_GET['pg']??1));$per=18;
        $products=get_posts(['post_type'=>'tager_product','post_status'=>'publish','numberposts'=>-1,'s'=>$q,'meta_key'=>'approval_status','meta_value'=>'approved']);
        $products=array_values(array_filter($products,function($p)use($gov,$center,$stock){$uid=$p->post_author;if($gov&&get_user_meta($uid,'tager_governorate',true)!==$gov)return false;if($center){$pc=get_user_meta($uid,'tager_center',true);$areas=(array)get_user_meta($uid,'tager_service_centers',true);if($pc!==$center&&!in_array($center,$areas,true))return false;}if($stock&&(float)get_post_meta($p->ID,'stock',true)<=0)return false;return true;}));
        usort($products,function($a,$b)use($sort,$tier){$pa=self::product_price($a->ID,$tier?:'retail');$pb=self::product_price($b->ID,$tier?:'retail');if($sort==='price_asc')return $pa<=>$pb;if($sort==='price_desc')return $pb<=>$pa;if($sort==='name')return strcasecmp($a->post_title,$b->post_title);return $b->ID<=>$a->ID;});
        $total=count($products);$products=array_slice($products,($page-1)*$per,$per);
        ob_start();?><div class="tv48"><section class="tv48-hero"><h1>سوق تاجر المتكامل</h1><p>ابحث قطاعي أو جملة أو جملة الجملة، مع فرز حسب السعر والموقع والتوفر.</p></section><form class="tv48-filters"><input name="q" value="<?php echo esc_attr($q);?>" placeholder="اسم المنتج أو العلامة"><select name="tier"><option value="">كل أنواع البيع</option><option value="retail" <?php selected($tier,'retail');?>>قطاعي</option><option value="wholesale" <?php selected($tier,'wholesale');?>>جملة</option><option value="bulk" <?php selected($tier,'bulk');?>>جملة الجملة</option></select><select name="gov" data-tv48-gov><option value="">كل المحافظات</option><?php foreach(self::govs() as $g=>$cs)echo '<option '.selected($gov,$g,false).'>'.esc_html($g).'</option>';?></select><select name="center" data-tv48-center><option value="">كل المراكز</option><?php foreach((self::govs()[$gov]??[]) as $c)echo '<option '.selected($center,$c,false).'>'.esc_html($c).'</option>';?></select><select name="sort"><option value="new">الأحدث</option><option value="price_asc" <?php selected($sort,'price_asc');?>>السعر الأقل</option><option value="price_desc" <?php selected($sort,'price_desc');?>>السعر الأعلى</option><option value="name" <?php selected($sort,'name');?>>الاسم</option></select><label><input type="checkbox" name="stock" value="1" <?php checked($stock);?>> المتاح فقط</label><button class="tv48-btn">تطبيق</button></form><div class="tv48-grid"><?php if(!$products)echo '<div class="tv48-empty">لا توجد منتجات مطابقة.</div>';foreach($products as $p){$id=$p->ID;$uid=$p->post_author;$vendor=get_userdata($uid);?><article class="tv48-card"><div class="tv48-media"><?php echo get_the_post_thumbnail($id,'medium')?:'<span style="font-size:52px">📦</span>';?></div><div class="tv48-body"><h3><?php echo esc_html($p->post_title);?></h3><a href="<?php echo esc_url(self::url('vendor-store',['vendor_id'=>$uid]));?>"><?php echo esc_html(get_user_meta($uid,'store_name',true)?:$vendor->display_name);?></a><div class="tv48-prices"><div class="tv48-price">قطاعي<strong><?php echo esc_html(get_post_meta($id,'retail_price',true));?> ج.م</strong></div><div class="tv48-price">جملة<strong><?php echo esc_html(get_post_meta($id,'wholesale_price',true));?> ج.م</strong><small><?php echo esc_html(get_post_meta($id,'wholesale_min',true));?>+</small></div><div class="tv48-price">جملة الجملة<strong><?php echo esc_html(get_post_meta($id,'bulk_price',true));?> ج.م</strong><small><?php echo esc_html(get_post_meta($id,'bulk_min',true));?>+</small></div></div><div class="tv48-tags"><span class="tv48-tag">مخزون <?php echo esc_html(get_post_meta($id,'stock',true));?></span><span class="tv48-tag"><?php echo esc_html(get_user_meta($uid,'tager_governorate',true));?></span></div><a class="tv48-btn alt" href="<?php echo esc_url(self::url('product',['product_id'=>$id]));?>">عرض المنتج</a></div></article><?php }?></div><?php $pages=(int)ceil($total/$per);if($pages>1){echo '<div class="tv48-pager">';for($i=1;$i<=$pages;$i++)echo $i===$page?'<span>'.$i.'</span>':'<a href="'.esc_url(add_query_arg('pg',$i)).'">'.$i.'</a>';echo '</div>';}?></div><?php return ob_get_clean();
    }
    public static function vendor_profile(){
        if(!is_user_logged_in()||!self::vendor_ok(get_current_user_id()))return '<div class="tv48-empty">هذه الصفحة للموردين فقط.</div>';$uid=get_current_user_id();$gov=get_user_meta($uid,'tager_governorate',true);$center=get_user_meta($uid,'tager_center',true);$areas=(array)get_user_meta($uid,'tager_service_centers',true);$all=self::govs();ob_start();?><div class="tv48"><div class="tv48-form"><h1>بيانات المورد ومناطق الخدمة</h1><?php if(!empty($_GET['saved']))echo '<p class="tv48-tag">تم الحفظ بنجاح</p>';?><form method="post" action="<?php echo esc_url(admin_url('admin-post.php'));?>"><input type="hidden" name="action" value="tager_v48_save_profile"><?php wp_nonce_field('tager_v48_save_profile');?><label>اسم المتجر<input name="store_name" required value="<?php echo esc_attr(get_user_meta($uid,'store_name',true));?>"></label><label>المحافظة الرئيسية<select name="governorate" required data-tv48-gov><option value="">اختر</option><?php foreach($all as $g=>$cs)echo '<option '.selected($gov,$g,false).'>'.esc_html($g).'</option>';?></select></label><label>المركز الرئيسي<select name="center" required data-tv48-center><option value="">اختر</option><?php foreach(($all[$gov]??[]) as $c)echo '<option '.selected($center,$c,false).'>'.esc_html($c).'</option>';?></select></label><label>مراكز خدمة إضافية</label><div class="tv48-checks"><?php foreach(($all[$gov]??[]) as $c)echo '<label><input type="checkbox" name="service_centers[]" value="'.esc_attr($c).'" '.checked(in_array($c,$areas,true),true,false).'> '.esc_html($c).'</label>';?></div><label>الحد الأدنى للطلب<input type="number" min="0" step="0.01" name="min_order" value="<?php echo esc_attr(get_user_meta($uid,'vendor_min_order',true));?>"></label><label><input type="checkbox" name="delivery" value="1" <?php checked(get_user_meta($uid,'tager_delivery_available',true));?>> التوصيل متاح</label><label>مدة التوصيل المتوقعة<input name="delivery_time" value="<?php echo esc_attr(get_user_meta($uid,'tager_delivery_time',true));?>" placeholder="مثال: 1-3 أيام"></label><label>نبذة عن النشاط<textarea name="description" rows="5"><?php echo esc_textarea(get_user_meta($uid,'store_description',true));?></textarea></label><button class="tv48-btn">حفظ البيانات</button></form></div></div><?php return ob_get_clean();
    }
    public static function save_profile(){
        if(!is_user_logged_in()||!self::vendor_ok(get_current_user_id()))wp_die('Not allowed');check_admin_referer('tager_v48_save_profile');$uid=get_current_user_id();$gov=sanitize_text_field($_POST['governorate']??'');$center=sanitize_text_field($_POST['center']??'');$map=self::govs();if(!isset($map[$gov])||!in_array($center,$map[$gov],true))wp_die('Invalid location');$areas=array_values(array_intersect(array_map('sanitize_text_field',(array)($_POST['service_centers']??[])),$map[$gov]));update_user_meta($uid,'store_name',sanitize_text_field($_POST['store_name']??''));update_user_meta($uid,'tager_governorate',$gov);update_user_meta($uid,'tager_center',$center);update_user_meta($uid,'tager_service_centers',$areas);update_user_meta($uid,'vendor_min_order',max(0,(float)($_POST['min_order']??0)));update_user_meta($uid,'tager_delivery_available',!empty($_POST['delivery'])?1:0);update_user_meta($uid,'tager_delivery_time',sanitize_text_field($_POST['delivery_time']??''));update_user_meta($uid,'store_description',sanitize_textarea_field($_POST['description']??''));wp_safe_redirect(add_query_arg('saved','1',self::url('vendor-location-settings')));exit;
    }
}
Tager_V48_Discovery_Upgrade::init();
